import xml.etree.ElementTree as ET
from xml.dom import minidom

def validate_xml(xml_file):
    try:
        tree = ET.parse(xml_file)
        root = tree.getroot()
        
        # Validate the structure of the XML document
        if not isinstance(root, ET.Element) or not list(root):
            return "Invalid XML structure"
        
        # Check for required elements
        required_elements = ['name', 'age', 'city']  # Define your required elements here
        if not all(child.tag in root.keys() for child in root if child.tag in required_elements):
            return "Missing required element(s)"
        
        # Validate the data type of the elements
        try:
            for elem in root.iter():
                if elem.text is None or len(elem.text.strip()) == 0:
                    continue
                elif elem.tag.lower() == 'age':
                    if not isinstance(int(elem.text), int):
                        return "Invalid age: {}".format(elem.text)
                # Add more data type validations as needed
        except ValueError:
            return "Invalid value for an element"
        
        # Return a success message or the XML document parsed into a string
        return minidom.parseString(ET.tostring(root)).toprettyxml(indent="   ")
    
    except FileNotFoundError:
        return "File not found: {}".format(xml_file)
    except ET.ParseError as e:
        return "XML parse error: {}".format(str(e))

# Example usage
